import redis
import os
from typing import Optional, Any
import json
import logging

logger = logging.getLogger(__name__)


class RedisClient:
    """Singleton Redis client for HealthBridge infrastructure."""

    _instance: Optional['RedisClient'] = None

    def __new__(cls) -> 'RedisClient':
        if cls._instance is None:
            cls._instance = super().__new__(cls)
            cls._instance._initialized = False
        return cls._instance

    def __init__(self):
        if self._initialized:
            return
        self._host = os.environ.get('REDIS_HOST', 'localhost')
        self._port = int(os.environ.get('REDIS_PORT', '6379'))
        self._db = int(os.environ.get('REDIS_DB', '0'))
        self._password = os.environ.get('REDIS_PASSWORD', None)
        self._pool = redis.ConnectionPool(
            host=self._host,
            port=self._port,
            db=self._db,
            password=self._password,
            decode_responses=True
        )
        self._client = redis.Redis(connection_pool=self._pool)
        self._initialized = True
        logger.info(f"Redis client initialized: {self._host}:{self._port}/{self._db}")

    @property
    def client(self) -> redis.Redis:
        return self._client

    def set_json(self, key: str, value: Any, ttl: Optional[int] = None) -> bool:
        """Store a JSON-serializable value with optional TTL in seconds."""
        try:
            serialized = json.dumps(value)
            if ttl:
                return self._client.setex(key, ttl, serialized)
            return self._client.set(key, serialized)
        except (json.JSONEncodeError, redis.RedisError) as e:
            logger.error(f"Redis set_json error for key {key}: {e}")
            return False

    def get_json(self, key: str) -> Optional[Any]:
        """Retrieve and deserialize a JSON value."""
        try:
            raw = self._client.get(key)
            if raw is None:
                return None
            return json.loads(raw)
        except (json.JSONDecodeError, redis.RedisError) as e:
            logger.error(f"Redis get_json error for key {key}: {e}")
            return None

    def delete(self, key: str) -> bool:
        """Delete a key."""
        try:
            return bool(self._client.delete(key))
        except redis.RedisError as e:
            logger.error(f"Redis delete error for key {key}: {e}")
            return False

    def exists(self, key: str) -> bool:
        """Check if key exists."""
        try:
            return bool(self._client.exists(key))
        except redis.RedisError as e:
            logger.error(f"Redis exists error for key {key}: {e}")
            return False

    def ttl(self, key: str) -> int:
        """Get remaining TTL for a key. Returns -1 if no TTL, -2 if key doesn't exist."""
        try:
            return self._client.ttl(key)
        except redis.RedisError as e:
            logger.error(f"Redis ttl error for key {key}: {e}")
            return -2

